class PaymentLimitExceededException extends RuntimeException {
    PaymentLimitExceededException(String message) {
        super(message);
    }
}

class PaymentService {
    void charge(Merchant merchant, BigDecimal amount) {
        if (amount.compareTo(merchant.getLimit()) > 0) {
            throw new PaymentLimitExceededException(
                "Amount exceeds merchant limit of " + merchant.getLimit());
        }
        // process the charge
    }
}

@ControllerAdvice
class ApiExceptionHandler {
    @ExceptionHandler(PaymentLimitExceededException.class)
    ResponseEntity<String> handle(PaymentLimitExceededException e) {
        return ResponseEntity.status(422).body(e.getMessage());
    }
}

