class OrderQueue {
    private final Queue<Order> orders = new LinkedList<>();

    synchronized void addOrder(Order order) {
        orders.add(order);
        notify();
    }

    synchronized Order takeOrder() throws InterruptedException {
        while (orders.isEmpty()) {
            wait();
        }
        return orders.poll();
    }
}

